q05.sparql:
# Q05 — Crescita del numero di pensioni nelle 5 sedi INPS più popolose,
# dal 1998 al 2026 (28 anni).
#
# Cosa mostra: Variazione percentuale del numero di pensioni fra il 1998 e il 2026 nelle cinque sedi INPS più popolose d'Italia.

PREFIX qb:    <http://purl.org/linked-data/cube#>
PREFIX skos:  <http://www.w3.org/2004/02/skos/core#>
PREFIX idpt:  <https://robertobrunocl.github.io/idpt-italia/>
PREFIX xsd:   <http://www.w3.org/2001/XMLSchema#>

SELECT ?sede ?n_1998 ?n_2026
       (xsd:decimal(?n_2026 - ?n_1998) / ?n_1998 * 100 AS ?crescita_pct)
WHERE {
  VALUES ?sede_uri {
    idpt:sede-inps-torino
    idpt:sede-inps-milano
    idpt:sede-inps-roma
    idpt:sede-inps-napoli
    idpt:sede-inps-brescia
  }
  ?obs98 qb:dataSet idpt:cubo-pensioni-serie-storica-sede ;
         idpt:sedeINPS ?sede_uri ;
         idpt:annoRiferimento "1998"^^xsd:gYear ;
         qb:measureType idpt:numeroPensioni ;
         idpt:numeroPensioni ?n_1998 .
  ?obs26 qb:dataSet idpt:cubo-pensioni-serie-storica-sede ;
         idpt:sedeINPS ?sede_uri ;
         idpt:annoRiferimento "2026"^^xsd:gYear ;
         qb:measureType idpt:numeroPensioni ;
         idpt:numeroPensioni ?n_2026 .
  ?sede_uri skos:prefLabel ?sede .
  FILTER(LANG(?sede) = "it")
}
ORDER BY DESC(?crescita_pct)

q09.sparql:
# Q09 — Quintupla identità Palermo: AGID + NUTS + DBpedia + altLabel-INPS + Sede.
#
# Cosa mostra: I sette punti di identità semantica della provincia di Palermo nel Linked Open Data Cloud.

PREFIX skos:  <http://www.w3.org/2004/02/skos/core#>
PREFIX clv:   <https://w3id.org/italia/onto/CLV/>
PREFIX owl:   <http://www.w3.org/2002/07/owl#>
PREFIX idpt:  <https://robertobrunocl.github.io/idpt-italia/>
PREFIX agidp: <https://w3id.org/italia/controlled-vocabulary/territorial-classifications/provinces/>

SELECT ?relation ?value
WHERE {
  {
    BIND("AGID URI canonica" AS ?relation)
    BIND(STR(agidp:082) AS ?value)
  } UNION {
    BIND("AGID prefLabel @it" AS ?relation)
    agidp:082 skos:prefLabel ?value . FILTER(LANG(?value) = "it")
  } UNION {
    BIND("Sigla AGID" AS ?relation)
    agidp:082 clv:acronym ?value
  } UNION {
    BIND("NUTS via owl:sameAs" AS ?relation)
    agidp:082 owl:sameAs ?nuts .
    FILTER(STRSTARTS(STR(?nuts), "http://nuts.geovocab.org/"))
    BIND(STR(?nuts) AS ?value)
  } UNION {
    BIND("DBpedia via owl:sameAs" AS ?relation)
    agidp:082 owl:sameAs ?dbp .
    FILTER(STRSTARTS(STR(?dbp), "http://dbpedia.org/"))
    BIND(STR(?dbp) AS ?value)
  } UNION {
    BIND("skos:altLabel @it-x-inps (forma INPS originale)" AS ?relation)
    agidp:082 skos:altLabel ?al . FILTER(LANG(?al) = "it-x-inps")
    BIND(STR(?al) AS ?value)
  } UNION {
    BIND("Sede INPS (idpt:SedeINPS)" AS ?relation)
    ?sede idpt:correspondsToProvinceAGID agidp:082 .
    BIND(STR(?sede) AS ?value)
  }
}

q10.sparql:
# Q10 — Quota di pensioni in regime retributivo per regione (group-by
# clv:situatedWithin).
#
# Cosa mostra: Percentuale di pensioni ancora in regime retributivo puro (pre-Riforma Dini 1995) in ognuna delle 20 regioni italiane.

PREFIX qb:    <http://purl.org/linked-data/cube#>
PREFIX skos:  <http://www.w3.org/2004/02/skos/core#>
PREFIX clv:   <https://w3id.org/italia/onto/CLV/>
PREFIX idpt:  <https://robertobrunocl.github.io/idpt-italia/>
PREFIX xsd:   <http://www.w3.org/2001/XMLSchema#>

SELECT ?regione
       (SUM(?n_retr) AS ?totale_retr)
       (SUM(?n_tot)  AS ?totale_pensioni)
       (xsd:decimal(SUM(?n_retr)) / SUM(?n_tot) AS ?quota_retr)
WHERE {
  ?obs_r qb:dataSet idpt:cubo-pensioni-regime-sede ;
         idpt:sedeINPS ?sede ;
         idpt:regimeLiquidazione idpt:regime-retributivo ;
         qb:measureType idpt:numeroPensioni ;
         idpt:numeroPensioni ?n_retr .
  ?sede idpt:correspondsToProvinceAGID ?prov .
  ?prov clv:situatedWithin ?reg .
  ?reg skos:prefLabel ?regione .
  FILTER(LANG(?regione) = "it")

  ?obs_t qb:dataSet idpt:cubo-pensioni-vigenti-residenza ;
         idpt:provincia ?prov ;
         idpt:tipoGestione idpt:gestione-totale ;
         idpt:numeroPensioni ?n_tot .
}
GROUP BY ?regione
ORDER BY DESC(?quota_retr)

q12.sparql:
# Q12 — Durata attesa stimata di una pensione di vecchiaia, provincia per
# provincia, basata su LIFEEXP65T ISTAT 2025 e sull'età media alla decorrenza
# GDP nazionale del decennio 2020-2025.
#
# Cosa mostra: Durata media attesa di una pensione di vecchiaia per ognuna delle 107 province italiane.

PREFIX qb:    <http://purl.org/linked-data/cube#>
PREFIX skos:  <http://www.w3.org/2004/02/skos/core#>
PREFIX clv:   <https://w3id.org/italia/onto/CLV/>
PREFIX idpt:  <https://robertobrunocl.github.io/idpt-italia/>
PREFIX xsd:   <http://www.w3.org/2001/XMLSchema#>

SELECT ?sigla ?provincia ?lifeexp65 ?eta_decorrenza_2020s ?durata_attesa_pensione
WHERE {
  # ------ LIFEEXP65T provincia per provincia (cubo 6, riferimento 2025) ------
  ?obs_l qb:dataSet idpt:cubo-indicatori-demografici-istat ;
         idpt:provincia ?p ;
         idpt:indicatoreDemografico idpt:ind-lifeexp65t ;
         idpt:valoreIndicatore ?lifeexp65 .
  ?p clv:acronym    ?sigla ;
     skos:prefLabel ?provincia .
  FILTER(LANG(?provincia) = "it")

  # ------ Subquery: età media nazionale alla decorrenza GDP, decennio 2020-2025 ------
  {
    SELECT (xsd:decimal(SUM(?eta * ?n)) / SUM(?n) AS ?eta_decorrenza_2020s)
    WHERE {
      ?obs_d qb:dataSet idpt:cubo-pensioni-decorrenza-gdp ;
             idpt:annoDecorrenza ?anno ;
             idpt:etaMediaDecorrenza ?eta ;
             idpt:numeroPensioni ?n .
      FILTER(xsd:integer(STR(?anno)) >= 2020)
    }
  }

  # ------ Stima durata attesa ------
  BIND(?lifeexp65 + 65 - ?eta_decorrenza_2020s AS ?durata_attesa_pensione)
}
ORDER BY DESC(?durata_attesa_pensione)
